import{_ as t}from"./chunks/文件受限图.DsG20F9s.js";import{_ as e,o as l,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"图像审查与访问模式","description":"","frontmatter":{},"headers":[],"relativePath":"cn/Safety/image-moderation-and-access-mode.md","filePath":"cn/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),d={name:"cn/Safety/image-moderation-and-access-mode.md"};function o(h,a,p,n,s,c){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="图像审查与访问模式" tabindex="-1">图像审查与访问模式 <a class="header-anchor" href="#图像审查与访问模式" aria-label="Permalink to &quot;图像审查与访问模式&quot;">​</a></h1><p>“图像审查”用于给上传的图片设置年龄分级，并通过“访问模式”控制公开访问时能看到哪些内容。</p><p>这个设置会影响公开图床、公开 URL 链接和随机图接口。后台管理页不受这个访问模式限制，管理员仍然可以查看和管理全部文件。</p><h2 id="功能入口" tabindex="-1">功能入口 <a class="header-anchor" href="#功能入口" aria-label="Permalink to &quot;功能入口&quot;">​</a></h2><p>进入后台后，打开：</p><p>系统配置 → 安全设置 → 上传管理 → 图像审查</p><p>这里主要有三个设置：</p><ul><li>访问模式</li><li>开启审查</li><li>审查渠道</li></ul><h2 id="访问模式是做什么的" tabindex="-1">访问模式是做什么的 <a class="header-anchor" href="#访问模式是做什么的" aria-label="Permalink to &quot;访问模式是做什么的&quot;">​</a></h2><p>访问模式决定公开访问时允许展示到哪个年龄分级。</p><p>当前有四档：</p><table tabindex="0"><thead><tr><th>访问模式</th><th>公开可见范围</th></tr></thead><tbody><tr><td>成人模式</td><td>全年龄、R12、R16、R18</td></tr><tr><td>青年模式</td><td>全年龄、R12、R16</td></tr><tr><td>少年模式</td><td>全年龄、R12</td></tr><tr><td>儿童模式</td><td>仅全年龄</td></tr></tbody></table><p>默认是成人模式。</p><p>如果你的站点是自用或成人内容较多，可以保持成人模式。如果你希望公开图床更保守，可以改成青年、少年或儿童模式。</p><h2 id="开启审查是做什么的" tabindex="-1">开启审查是做什么的 <a class="header-anchor" href="#开启审查是做什么的" aria-label="Permalink to &quot;开启审查是做什么的&quot;">​</a></h2><p>开启审查后，系统会在上传时调用你选择的审查渠道，对图片进行识别，并写入对应的年龄分级。</p><p>年龄分级主要有：</p><table tabindex="0"><thead><tr><th>分级</th><th>含义</th></tr></thead><tbody><tr><td>全年龄</td><td>普通公开内容</td></tr><tr><td>R12</td><td>轻度敏感内容</td></tr><tr><td>R16</td><td>中度敏感内容</td></tr><tr><td>R18</td><td>成人内容</td></tr></tbody></table><p>审查结果会参与公开访问判断。</p><p>如果没有开启审查，或者某些旧文件还没有分级，这些文件会按未分级处理。未分级文件不会因为没有分级结果就自动从公开图床和随机图里消失。</p><h2 id="审查渠道怎么选" tabindex="-1">审查渠道怎么选 <a class="header-anchor" href="#审查渠道怎么选" aria-label="Permalink to &quot;审查渠道怎么选&quot;">​</a></h2><p>当前审查渠道包括：</p><ul><li>moderatecontent.com</li><li>nsfwjs</li><li>Sightengine</li></ul><p>不同渠道需要的配置不同：</p><ul><li>moderatecontent.com 通常需要 API Key。</li><li>nsfwjs 通常需要填写接口地址。</li><li>Sightengine 需要 API 用户和 API 密钥。</li></ul><p>选择哪个渠道，取决于你自己的账号、服务可用性和识别效果。只要开启审查并配置正确，上传时就会尝试写入图片分级。</p><h2 id="对公开图床的影响" tabindex="-1">对公开图床的影响 <a class="header-anchor" href="#对公开图床的影响" aria-label="Permalink to &quot;对公开图床的影响&quot;">​</a></h2><p>公开图床列表会按访问模式过滤内容。</p><p>例如：</p><ul><li>成人模式：公开图床可以显示 R18 图片。</li><li>青年模式：公开图床不会显示 R18 图片。</li><li>少年模式：公开图床不会显示 R16 和 R18 图片。</li><li>儿童模式：公开图床只显示全年龄图片。</li></ul><p>这只是影响普通公开访问。后台管理页仍然可以看到全部文件。</p><h2 id="对公开-url-链接的影响" tabindex="-1">对公开 URL 链接的影响 <a class="header-anchor" href="#对公开-url-链接的影响" aria-label="Permalink to &quot;对公开 URL 链接的影响&quot;">​</a></h2><p>公开 URL 链接就是用户直接访问图片链接时的场景。</p><p>如果图片分级在当前访问模式允许范围内，系统会正常返回原图。</p><p>如果图片分级超过当前访问模式，普通访问不会返回原图，而是返回拦截结果或提示图。</p><p>例如：</p><ul><li>当前是儿童模式。</li><li>某张图是 R18。</li><li>用户直接打开这张图的公开链接。</li><li>系统不会把 R18 原图返回给普通用户。</li></ul><p><img src="'+t+'" alt="文件受限图" loading="lazy"></p><p>管理员在后台查看文件时不受这个限制。</p><h2 id="对随机图的影响" tabindex="-1">对随机图的影响 <a class="header-anchor" href="#对随机图的影响" aria-label="Permalink to &quot;对随机图的影响&quot;">​</a></h2><p>随机图接口也会按访问模式过滤候选池。</p><p>如果当前是儿童模式，随机图只会从全年龄图片里抽取。</p><p>如果当前是青年模式，随机图可以从全年龄、R12、R16 图片里抽取，但不会抽到 R18 图片。</p><p>这样可以避免随机图接口绕过公开图床的访问限制。</p><h2 id="和名单规则的关系" tabindex="-1">和名单规则的关系 <a class="header-anchor" href="#和名单规则的关系" aria-label="Permalink to &quot;和名单规则的关系&quot;">​</a></h2><p>访问模式不是唯一的公开访问规则，它会和名单规则一起生效。</p><p>简单理解：</p><ul><li>白名单内容优先公开。</li><li>黑名单内容普通用户不能直接看到原图。</li><li>不在名单里的内容，再按访问模式判断是否允许公开。</li></ul><p>如果一张图片同时被年龄分级限制和名单规则限制，普通用户仍然不能直接看到原图。</p><h2 id="推荐设置" tabindex="-1">推荐设置 <a class="header-anchor" href="#推荐设置" aria-label="Permalink to &quot;推荐设置&quot;">​</a></h2><p>公开站点建议：</p><ul><li>开启审查。</li><li>按站点定位选择访问模式。</li><li>面向全年龄用户时选择儿童模式或少年模式。</li><li>不希望公开展示成人内容时不要使用成人模式。</li><li>定期检查后台文件分级，必要时手动调整。</li></ul><p>私人站点或自用站点可以：</p><ul><li>使用成人模式。</li><li>按需要开启审查。</li><li>通过后台管理页查看和调整分级。</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="改了访问模式-后台文件会不会消失" tabindex="-1">改了访问模式，后台文件会不会消失？ <a class="header-anchor" href="#改了访问模式-后台文件会不会消失" aria-label="Permalink to &quot;改了访问模式，后台文件会不会消失？&quot;">​</a></h3><p>不会。</p><p>访问模式只影响普通公开访问，不影响后台管理页。</p><h3 id="改成儿童模式后-公开图床为什么少了很多图片" tabindex="-1">改成儿童模式后，公开图床为什么少了很多图片？ <a class="header-anchor" href="#改成儿童模式后-公开图床为什么少了很多图片" aria-label="Permalink to &quot;改成儿童模式后，公开图床为什么少了很多图片？&quot;">​</a></h3><p>因为儿童模式只允许全年龄图片公开展示。R12、R16、R18 图片会被过滤。</p><h3 id="公开-url-链接还会不会直接打开成人图片" tabindex="-1">公开 URL 链接还会不会直接打开成人图片？ <a class="header-anchor" href="#公开-url-链接还会不会直接打开成人图片" aria-label="Permalink to &quot;公开 URL 链接还会不会直接打开成人图片？&quot;">​</a></h3><p>如果当前访问模式不允许对应分级，普通公开 URL 不会返回原图。</p><h3 id="随机图会不会抽到被限制的图片" tabindex="-1">随机图会不会抽到被限制的图片？ <a class="header-anchor" href="#随机图会不会抽到被限制的图片" aria-label="Permalink to &quot;随机图会不会抽到被限制的图片？&quot;">​</a></h3><p>不会。</p><p>随机图会按当前访问模式过滤候选图片。</p><h3 id="没有分级的旧图片会怎样" tabindex="-1">没有分级的旧图片会怎样？ <a class="header-anchor" href="#没有分级的旧图片会怎样" aria-label="Permalink to &quot;没有分级的旧图片会怎样？&quot;">​</a></h3><p>未分级图片不会因为没有审查结果就自动隐藏。你可以在后台后续手动调整分级。</p>',67)])])}const q=e(d,[["render",o]]);export{b as __pageData,q as default};
